// Handle list item selection and detail display
function selectListItem(event) {
  // Remove previous selection
  document.querySelectorAll('.fd-list__item').forEach(item => {
    item.classList.remove('is-selected');
  });

  // Add selection to clicked item
  event.currentTarget.classList.add('is-selected');

  // Load detail content
  const itemId = event.currentTarget.dataset.id;
  loadDetailContent(itemId);
}

// Attach to all list items
document.querySelectorAll('.fd-list__item--link').forEach(item => {
  item.addEventListener('click', selectListItem);
});

javascriptPatterns.filtering:
// Filter list items by search term
function filterList(searchTerm) {
  const items = document.querySelectorAll('.fd-list__item');
  const term = searchTerm.toLowerCase();

  items.forEach(item => {
    const title = item.querySelector('.fd-list__title')?.textContent.toLowerCase() || '';
    const byline = item.querySelector('.fd-list__byline')?.textContent.toLowerCase() || '';

    if (title.includes(term) || byline.includes(term)) {
      item.style.display = '';
    } else {
      item.style.display = 'none';
    }
  });
}
